const currentStep = variables['fca96772-3cc2-4e28-a4e5-2249e3d8c713'];
const onboardingData = variables['c1aca85c-db91-4d3f-913b-1fbbb8ccc646'];

switch (currentStep) {
  case 1:
    // Welcome step - no validation needed
    return true;

  case 2:
    // Personal information step
    const displayName = onboardingData.display_name?.trim();
    const phone = onboardingData.phone?.trim();

    if (!displayName || displayName.length < 2) {
      return false;
    }
    if (!phone || phone.length < 10) {
      return false;
    }

    return true;

  case 3:
    // Profile picture step - optional, always valid
    return true;

  case 4:
    // User type step
    return true

  default:
    return false;
}
